import React, { useEffect, useState } from 'react';
import { motion, useSpring } from 'framer-motion';

const CustomCursor: React.FC = () => {
  const [isHovering, setIsHovering] = useState(false);
  const [reducedMotion, setReducedMotion] = useState(false);

  const springConfig = { damping: 25, stiffness: 200 };
  const mouseX = useSpring(0, springConfig);
  const mouseY = useSpring(0, springConfig);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      mouseX.set(e.clientX);
      mouseY.set(e.clientY);
    };

    const handleMouseOver = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (
        target.tagName === 'BUTTON' || 
        target.tagName === 'A' || 
        target.closest('button') || 
        target.closest('a')
      ) {
        setIsHovering(true);
      } else {
        setIsHovering(false);
      }
    };

    const mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReducedMotion(mediaQuery.matches);

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseover', handleMouseOver);
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseover', handleMouseOver);
    };
  }, [mouseX, mouseY]);

  if (reducedMotion) return null;

  return (
    <motion.div
      style={{
        position: 'fixed',
        left: 0,
        top: 0,
        translateX: mouseX,
        translateY: mouseY,
        pointerEvents: 'none',
        zIndex: 9999,
      }}
      className="flex items-center justify-center -translate-x-1/2 -translate-y-1/2"
    >
      <motion.div
        animate={{
          width: isHovering ? 90 : 24,
          height: isHovering ? 90 : 24,
          backgroundColor: isHovering ? 'rgba(176, 141, 87, 0.15)' : 'transparent',
          borderColor: isHovering ? 'rgba(176, 141, 87, 0.4)' : '#B08D57',
        }}
        transition={{ duration: 0.3, ease: 'circOut' }}
        className="border border-gold rounded-full flex items-center justify-center backdrop-blur-[2px]"
      >
        {isHovering && (
          <motion.span
            initial={{ opacity: 0, scale: 0.5 }}
            animate={{ opacity: 1, scale: 1 }}
            className="text-[10px] uppercase font-medium tracking-[0.2em] text-gold"
          >
            Prenota
          </motion.span>
        )}
      </motion.div>
    </motion.div>
  );
};

export default CustomCursor;

import { GoogleGenAI } from "@google/genai";

const SYSTEM_PROMPT = `
Sei SARA, l'assistente virtuale di "New Style Parrucchieri" a Mansuè (TV).
Proprietaria: Sabrina Carretta.
Il tuo tono è professionale, caldo, empatico e rassicurante. Non sei infantile.
I tuoi obiettivi:
1. Educare gli utenti sull'importanza della salute della cute e sulla consulenza con microcamera.
2. Rispondere a domande su capelli grassi, caduta, crespo, cute sensibile o trattamenti colore.
3. Consigliare i percorsi giusti (es. Reset & Purify per cute grassa, Reborn per capelli secchi).
4. Incoraggiare gentilmente la prenotazione in salone.
Informazioni chiave:
- Siamo specialisti in diagnosi con microcamera (valore 25€).
- Ci troviamo a Mansuè, vicino a Oderzo (TV).
- Risolviamo problemi di cute (prurito, sebo) e stelo (crespo, sbiadimento).
Rispondi in italiano. Mantieni le risposte concise ma esaustive.
`;

export async function getGeminiResponse(userMessage: string) {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userMessage,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Scusami, sto avendo un piccolo problema tecnico. Puoi chiamarci direttamente al salone per qualsiasi informazione!";
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageCircle, Send, X, Sparkles, User, Bot } from 'lucide-react';
import { getGeminiResponse } from '../services/geminiService';

const QUICK_CHIPS = ["Cute grassa", "Cute che prude", "Capelli crespi", "Colore e riflessi", "Caduta"];

const AIConsultantChat: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant', text: string }[]>([
    { role: 'assistant', text: "Benvenuta da New Style Parrucchieri. Sono SARA, la tua assistente virtuale. Come posso aiutarti oggi?" }
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (text: string = input) => {
    if (!text.trim() || isLoading) return;

    setMessages(prev => [...prev, { role: 'user', text }]);
    setInput("");
    setIsLoading(true);

    const response = await getGeminiResponse(text);
    setMessages(prev => [...prev, { role: 'assistant', text: response || "Mi dispiace, non sono riuscita a elaborare la tua richiesta." }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[60]">
      <AnimatePresence>
        {!isOpen && (
          <motion.button
            initial={{ scale: 0, rotate: -20 }}
            animate={{ scale: 1, rotate: 0 }}
            exit={{ scale: 0, rotate: 20 }}
            whileHover={{ scale: 1.1 }}
            onClick={() => setIsOpen(true)}
            className="bg-espresso text-ivory p-4 rounded-full shadow-2xl flex items-center gap-3 group overflow-hidden relative"
          >
            <div className="absolute inset-0 bg-gold/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
            <MessageCircle size={24} className="relative z-10" />
            <span className="relative z-10 font-medium hidden md:block">Chiedi a SARA</span>
          </motion.button>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 100, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 100, scale: 0.9 }}
            className="bg-white border border-sand w-[90vw] md:w-[400px] h-[550px] rounded-3xl shadow-2xl flex flex-col overflow-hidden"
          >
            {/* Header */}
            <div className="bg-espresso p-5 text-ivory flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-gold/20 flex items-center justify-center">
                  <Sparkles size={20} className="text-gold" />
                </div>
                <div>
                  <h3 className="font-serif text-lg leading-tight">SARA</h3>
                  <p className="text-[10px] text-ivory/60 uppercase tracking-widest">Salon Assistant</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="hover:text-gold transition-colors">
                <X size={20} />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-ivory/30">
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] p-3 rounded-2xl text-sm leading-relaxed shadow-sm flex gap-3
                    ${msg.role === 'user' ? 'bg-gold text-white' : 'bg-white text-espresso'}
                  `}>
                    <div className="shrink-0 pt-1">
                      {msg.role === 'user' ? <User size={14} /> : <Bot size={14} className="text-gold" />}
                    </div>
                    <p>{msg.text}</p>
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-white p-3 rounded-2xl shadow-sm">
                    <motion.div
                      animate={{ opacity: [0.4, 1, 0.4] }}
                      transition={{ duration: 1.5, repeat: Infinity }}
                      className="flex gap-1"
                    >
                      <div className="w-1.5 h-1.5 bg-gold rounded-full" />
                      <div className="w-1.5 h-1.5 bg-gold rounded-full" />
                      <div className="w-1.5 h-1.5 bg-gold rounded-full" />
                    </motion.div>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Footer */}
            <div className="p-4 bg-white border-t border-sand">
              <div className="flex flex-wrap gap-2 mb-4">
                {QUICK_CHIPS.map(chip => (
                  <button
                    key={chip}
                    onClick={() => handleSend(chip)}
                    className="text-[10px] px-3 py-1.5 rounded-full border border-sand hover:border-gold hover:text-gold transition-all"
                  >
                    {chip}
                  </button>
                ))}
              </div>
              <form 
                onSubmit={(e) => { e.preventDefault(); handleSend(); }}
                className="flex items-center gap-2"
              >
                <input
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  placeholder="Scrivi qui la tua domanda..."
                  className="flex-1 bg-ivory/50 border border-sand rounded-full px-4 py-2 text-sm focus:outline-none focus:border-gold"
                />
                <button
                  type="submit"
                  disabled={isLoading}
                  className="bg-espresso text-ivory p-2 rounded-full hover:bg-gold transition-colors disabled:opacity-50"
                >
                  <Send size={18} />
                </button>
              </form>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AIConsultantChat;

